var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"도착했네. 이 앞이 재건 도시야.","JPN":"着いた。この先が再建都市だ。","ENG":"We're here. Just ahead is the Rebuilt City.","TWN":"到了，前面就是重建城市。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"태워줘서 고마워.","JPN":"乗せてくれたこと、感謝する。","ENG":"Thanks for the ride.","TWN":"謝謝你載我來。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"도시라는 이름에 비하면, 별로 번화해 보이진 않지만 말이지.","JPN":"都市という名のわりには、あまり賑わっているようには見えないな。","ENG":"Though for something called a city, it doesn't look that bustling.","TWN":"但這裡好像談不上是一座城市，沒有城市的繁華感。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>재건</color>도시니까요. 여긴 얼마 전까지만 해도 사람이 못 사는 폐허였어요.","JPN":"<color=#ffd34c>再建</color>都市ですからね。ちょっと前までは人が住めない廃墟でした。","ENG":"Well, it's been <color=#ffd34c>rebuilt</color>. This place was just ruins no one could live in until recently.","TWN":"因為是<color=#ffd34c>重建</color>城市。這裡在不久前都還是個無人居住的廢墟。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"관리국이 본격적으로 재건을 시작한 지는 아직 2개월 밖에 안 됐거든요.","JPN":"管理局が本格的に再建を始めて、まだ2か月しか経ってないんです。","ENG":"The Administration only started rebuilding here about two months ago.","TWN":"管理局正式開始重建也才兩個月。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신들, 고철을 아주 많이도 싣고 왔던데.","JPN":"お前たち、鉄くずをかなり多く積んでいたが。","ENG":"You guys brought a mountain of scrap metal with you.","TWN":"你們車上載了很多廢鐵。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"관리국에 무기 납품이라도 하는 건가?","JPN":"管理局に武器の納品でもしているのか？","ENG":"Supplying weapons to the Administration or something?","TWN":"是給管理局送武器嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이게 뭔지 궁금하다면 따라와도 상관없네. 바쁘지 않다면 말이야.","JPN":"気になるなら付いて来ても構わん。他に用事がなければだが。","ENG":"If you're curious, you're welcome to tag along. Assuming you're not busy.","TWN":"好奇的話可以一起來，如果你不忙的話。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"참.","JPN":"そうだ。","ENG":"Oh, right.","TWN":"對了。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"아이들은 좋아하는 편인가?","JPN":"子どもは好きか？","ENG":"Do you like kids?","TWN":"你喜歡小孩嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아이들?","JPN":"子ども？","ENG":"Kids?","TWN":"小孩？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"어, 사부님이다!","JPN":"わ、師匠だ！","ENG":"Hey, it's Mr. Seosaeng!","TWN":"哇，是老師！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"사부니임!! 가슴 큰 언니도 같이 왔네!","JPN":"師匠！！　胸のおっきなお姉さんもいっしょだ！","ENG":"Mr. Seosaeng! And you also brought your friend with big boobs too!","TWN":"老師！！胸部大的姊姊也來了！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"크, 흠! 그렇게 부르지 말래두.","JPN":"ご、ごほん！　そんな呼び方するんじゃないって。","ENG":"Ahem! I told you not to call me that.","TWN":"咳，咳！就叫你不要這樣叫我。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래. 다들 평안히 지내셨나?","JPN":"ああ、皆元気にしていたか？","ENG":"Good to see you all doing well.","TWN":"大家過得還好嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"이것 보세요! 사부님이 전에 가르쳐주신대로 만들었어요!","JPN":"これ見てください！　前に教えてもらったとおり作りました！","ENG":"Look! I made this just like you taught me!","TWN":"老師你看！我照老師教的做出來囉！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"굴뚝 청소 토끼 1호랑 2호요!","JPN":"煙突掃除うさぎ1号と2号！","ENG":"It's chimney-sweeper rabbit #1 and #2!","TWN":"煙囪清潔兔1號和2號！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"음… 내 안목이 틀리지 않았군.","JPN":"うむ……やはり某の目に狂いはなかったな。","ENG":"Hmm… Looks like I wasn't wrong about you.","TWN":"嗯…我的眼光沒錯。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"역시 두 사람에겐 소질이 있어. 작은 톱니 하나까지 흠결 없는 작품일세.","JPN":"2人には才能がある。小さな歯車の一つまで、非の打ち所のない作品だ。","ENG":"You really have a knack for this. Every gear is perfect.","TWN":"你們兩個人果然有天賦，連最小的齒輪都非常完美。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"에헤헤- 칭찬 받았다아-","JPN":"えへへ……ほめられた！","ENG":"Hehe! I got a compliment!","TWN":"嘿嘿嘿，被稱讚了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"다 사부님이 가르쳐주신 거잖아요.","JPN":"師匠のおかげです。","ENG":"It's all thanks to you.","TWN":"這都是老師教得好。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"나중엔 더 유용한 것도 만들어보고 싶어요. 사부님의 침식 경보 장치 같은 것처럼요.","JPN":"これからもっと役に立つものも作りたいです。師匠の侵食警報装置みたいな。","ENG":"Someday I want to make something really useful, like your Corruption alert device.","TWN":"我以後也想做出更有用的東西，像老師的侵蝕警報裝置一樣。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"좋은 마음가짐이야.","JPN":"よい心構えだ。","ENG":"That's a good goal.","TWN":"很棒的想法。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};